diff --git a/src/defrag.c b/src/defrag.c
index 5228143bb..241fa6052 100644
--- a/src/defrag.c
+++ b/src/defrag.c
@@ -1057,8 +1057,17 @@ static void endDefragCycle(bool normal_termination) {

 /* Must be called at the start of the timeProc as it measures the delay from the end of the previous
  * timeProc invocation when performing the computation. */
+static long getDefragMaxCycleUs(void) {
+    /* When a defrag time event is delayed, computeDefragCycleUs() can extend
+     * the next duty cycle to preserve the configured CPU percentage. Keep that
+     * starvation recovery bounded so a delayed timer cannot turn into a large
+     * client-visible latency spike. */
+    return server.active_defrag_cycle_us * 2;
+}
+
 static int computeDefragCycleUs(void) {
     long dutyCycleUs;
+    long maxCycleUs = getDefragMaxCycleUs();

     int targetCpuPercent = server.active_defrag_cpu_percent;
     serverAssert(targetCpuPercent > 0 && targetCpuPercent < 100);
@@ -1105,6 +1114,11 @@ static int computeDefragCycleUs(void) {
             dutyCycleUs = server.active_defrag_cycle_us;
         }
     }
+
+    if (dutyCycleUs > maxCycleUs) {
+        defrag.timeproc_overage_us += dutyCycleUs - maxCycleUs;
+        dutyCycleUs = maxCycleUs;
+    }
     return dutyCycleUs;
 }

 M src/defrag.c

